func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    // Create a deep copy of the grid
    newGrid := make([][]int64, len(grid))
    for i := range grid {
        newGrid[i] = make([]int64, len(grid[i]))
        copy(newGrid[i], grid[i])
    }

    // Iterate over each row in the submatrix
    for i := int64(0); i < k; i++ {
        originalRow := x + i
        mirroredRow := x + k - 1 - i

        // Only swap if the original row is before the mirrored row
        if originalRow < mirroredRow {
            // Swap the relevant portions of the rows
            for j := y; j < y + k; j++ {
                newGrid[originalRow][j], newGrid[mirroredRow][j] = newGrid[mirroredRow][j], newGrid[originalRow][j]
            }
        }
    }

    return newGrid
}
